    /**
     * Seeder para la tabla vehiculos.
     *
     * IMPORTANTE: Este seeder asume que la tabla `depositos` ya tiene datos.
     * Se utiliza un helper privado para obtener el id_deposito a partir del nombre
     * de la dependencia. Si no existe, se crea automáticamente.
     *
     * Los registros duplicados (mismo nro_movil) fueron deduplicados,
     * conservando la primera aparición de cada uno.
     */
    public function run(): void
    {
        $now = now();

        // Cache de depositos para evitar múltiples queries
        $depositoCache = [];

        // ID de fallback: primer depósito existente, usado cuando no se encuentra coincidencia
        $fallbackDepositoId = DB::table('depositos')->value('id') ?? 1;

        $getDepositoId = function (string $nombre) use (&$depositoCache, $fallbackDepositoId): int {
            $nombre = trim($nombre);
            if ($nombre === '') {
                return $fallbackDepositoId;
            }
            if (!isset($depositoCache[$nombre])) {
                $deposito = DB::table('depositos')
                    ->where('deposito', $nombre)
                    ->first();
                $depositoCache[$nombre] = $deposito ? $deposito->id : $fallbackDepositoId;
            }
            return $depositoCache[$nombre];
        };

